private void xrTableCell44_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal chickPlace = Convert.ToDecimal(GetCurrentColumnValue("ChickPlace") ?? 0);
decimal m1 = Convert.ToDecimal(GetCurrentColumnValue("M1") ?? 0);

if (chickPlace != 0)
{
    // Calculate: (M1 / ChickPlace) * 100
    // This gives mortality percentage for period 1
    decimal result = (m1 / chickPlace) * 100.0m;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}
}

