private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal chickPlace = Convert.ToDecimal(GetCurrentColumnValue("ChickPlace") ?? 0);
    decimal m1 = Convert.ToDecimal(GetCurrentColumnValue("M1") ?? 0);
    decimal c1 = Convert.ToDecimal(GetCurrentColumnValue("C1") ?? 0);
    decimal m2 = Convert.ToDecimal(GetCurrentColumnValue("M2") ?? 0);
    decimal c2 = Convert.ToDecimal(GetCurrentColumnValue("C2") ?? 0);
    decimal m3 = Convert.ToDecimal(GetCurrentColumnValue("M3") ?? 0);
    decimal c3 = Convert.ToDecimal(GetCurrentColumnValue("C3") ?? 0);
    decimal m4 = Convert.ToDecimal(GetCurrentColumnValue("M4") ?? 0);
    decimal c4 = Convert.ToDecimal(GetCurrentColumnValue("C4") ?? 0);
    decimal mortTillCatch = Convert.ToDecimal(GetCurrentColumnValue("MortTillCatch") ?? 0);
    decimal CullsTillCatch = Convert.ToDecimal(GetCurrentColumnValue("CullsTillCatch") ?? 0);
    decimal totalCullsMort = Convert.ToDecimal(GetCurrentColumnValue("TotalCullsMort") ?? 0);



    totalChickPlace += chickPlace;
    totalM1 += m1;
    totalC1 += c1;
    totalM2 += m2;
    totalC2 += c2;
    totalM3 += m3;
    totalC3 += c3;
    totalM4 += m4;
    totalC2 += c2;
    totalmortTillCatch += mortTillCatch ;
    totalCullsTillCatch += CullsTillCatch ;
    totalCullsMort += totalCullsMort;


}

private void xrTableCell79_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    if (totalChickPlace != 0)
    {
        decimal result = (totalM1 / totalChickPlace) * 100.0m;
        cell.Text = result.ToString("N2"); // Displays as 1.50 instead of 1.50%
    }
    else
    {
        cell.Text = "0.00";
    }
}

